     <style>
-        /* Specific overrides for this viz tool */
+        /* === FrankenTUI Base === */
+        :root {
+          --bg-color: #050505;
+          --fg-color: #33ff00;
+          --dim-color: #004400;
+          --accent-color: #bd00ff;
+          --error-color: #ff003c;
+          --panel-bg: #0a0a0a;
+          --border-color: #33ff00;
+          --grid-line: #112211;
+          --font-mono: 'JetBrains Mono', monospace;
+          --glow: 0 0 10px rgba(51, 255, 0, 0.2);
+        }
+        * { box-sizing: border-box; }
+        body {
+          background-color: var(--bg-color);
+          color: var(--fg-color);
+          font-family: var(--font-mono);
+          margin: 0;
+          overflow: hidden;
+          height: 100vh;
+          display: flex;
+          flex-direction: column;
+        }
+        .tui-header {
+          border-bottom: 2px solid var(--border-color);
+          padding: 0.5rem 1rem;
+          display: flex;
+          justify-content: space-between;
+          align-items: center;
+          text-transform: uppercase;
+          letter-spacing: 0.1em;
+        }
+        .tui-panel {
+          border: 1px solid var(--border-color);
+          background: var(--panel-bg);
+          position: relative;
+          display: flex;
+          flex-direction: column;
+          box-shadow: var(--glow);
+        }
+        .tui-panel::before {
+          content: "";
+          position: absolute;
+          top: -1px; left: -1px; right: -1px; bottom: -1px;
+          border: 1px dashed var(--dim-color);
+          pointer-events: none;
+          z-index: 1;
+        }
+        button {
+          background: transparent;
+          border: 1px solid var(--fg-color);
+          color: var(--fg-color);
+          font-family: var(--font-mono);
+          padding: 0.5rem 1rem;
+          cursor: pointer;
+          text-transform: uppercase;
+          transition: all 0.1s;
+        }
+        button:hover {
+          background: var(--fg-color);
+          color: var(--bg-color);
+          box-shadow: var(--glow);
+        }
+        button:active { transform: translateY(1px); }
+        input, select {
+          background: #000;
+          border: 1px solid var(--dim-color);
+          color: var(--fg-color);
+          font-family: var(--font-mono);
+          padding: 0.5rem;
+          width: 100%;
+        }
+        input:focus, select:focus {
+          border-color: var(--fg-color);
+          outline: none;
+          box-shadow: var(--glow);
+        }
+        ::-webkit-scrollbar { width: 10px; height: 10px; }
+        ::-webkit-scrollbar-track { background: var(--bg-color); border-left: 1px solid var(--dim-color); }
+        ::-webkit-scrollbar-thumb { background: var(--dim-color); border: 1px solid var(--bg-color); }
+        ::-webkit-scrollbar-thumb:hover { background: var(--fg-color); }
+        .hidden { display: none !important; }
+        .flex { display: flex; }
+        .gap-2 { gap: 0.5rem; }
+        .gap-3 { gap: 0.75rem; }
+        .gap-4 { gap: 1rem; }
+        .items-center { align-items: center; }
+        .justify-between { justify-content: space-between; }
+        .w-full { width: 100%; }
+        .h-full { height: 100%; }
+        .mt-4 { margin-top: 1rem; }
+        .mb-1 { margin-bottom: 0.25rem; }
+        .mb-2 { margin-bottom: 0.5rem; }
+        .mb-4 { margin-bottom: 1rem; }
+        .text-xs { font-size: 0.75rem; }
+        .text-xl { font-size: 1.25rem; }
+        .text-2xl { font-size: 1.5rem; }
+        .font-bold { font-weight: bold; }
+        .font-mono { font-family: var(--font-mono); }
+        .text-dim { color: var(--dim-color); }
+        .text-center { text-align: center; }
+        .text-white { color: #fff; }
+        .uppercase { text-transform: uppercase; }
+        .truncate { overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
+        .select-none { user-select: none; }
+        .cursor-pointer { cursor: pointer; }
+        .relative { position: relative; }
+        .absolute { position: absolute; }
+        .inset-0 { inset: 0; }
+        .flex-1 { flex: 1; }
+        .flex-col { flex-direction: column; }
+        .flex-shrink-0 { flex-shrink: 0; }
+        .overflow-hidden { overflow: hidden; }
+        .overflow-y-auto { overflow-y: auto; }
+        .pointer-events-none { pointer-events: none; }
+        .z-50 { z-index: 50; }
+
+        /* === Specific overrides for this viz tool === */
         .main-container { flex: 1; display: flex; overflow: hidden; position: relative; }
         .sidebar { width: 320px; border-right: 1px solid var(--dim-color); display: flex; flex-direction: column; background: var(--bg-color); flex-shrink: 0; }
         .content-area { flex: 1; display: flex; flex-direction: column; overflow: hidden; background: #080808; }
